// Função para buscar dados com segurança e evitar o erro de "Referenced node"
function getSafeData(nodeName) {
  try {
    return $(nodeName).item.json;
  } catch (e) {
    return {};
  }
}

// 1. Pega os dados dos nós (Certifique-se que os nomes estão 100% iguais no fluxo)
const webhookData = getSafeData('Webhook');
const sheetsData = getSafeData('Google Sheets');

// 2. Extrai a mensagem e o valor pago
const mensagem = webhookData?.body?.data?.message?.conversation || "";
const valorPagoMatch = mensagem.match(/\d+([.,]\d+)?/);
const valorPago = valorPagoMatch ? parseFloat(valorPagoMatch[0].replace(',', '.')) : 0;

// 3. Extrai o preço do item (Trata se vier como string ou número)
const precoRaw = sheetsData["Preço"] || sheetsData["Preco"] || "0";
const precoItem = parseFloat(String(precoRaw).replace(',', '.'));

// 4. Cálculo matemático
const troco = valorPago - precoItem;

return {
  resumo_financeiro: {
    item: sheetsData.Item || "Produto",
    preco: precoItem,
    pago: valorPago,
    troco: troco > 0 ? troco : 0,
    precisa_troco: valorPago > precoItem,
    status: (Object.keys(sheetsData).length === 0) ? "Aviso: Dados da planilha não encontrados no nó Code" : "OK"
  }
};

const items = $input.all();

const cardapioFormatado = items.map(item => {
  // O || '' garante que se o campo estiver vazio, o código não quebra
  const nome = item.json.Item || 'Prato';
  const preco = item.json.Preço || '---';
  const tamanho = item.json.Tamanho || ''; 

  let linhaTamanho = tamanho ? `\n└ 📏 Tamanho: ${tamanho}` : '';

  return `🍴 *${nome}*\n└ 💰 Valor: R$ ${preco}${linhaTamanho}\n`;
}).join('\n');

return { cardapio: `🌟 *CARDÁPIO DO DIA* 🌟\n\n${cardapioFormatado}` };
